// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract Crowdfunding {
	struct Campaign {
		address creator;
		string title;
		string description;
		uint256 goal;
		uint256 deadline;
		uint256 fundsRaised;
		bool claimed;
	}

	uint256 public nextCampaignId;
	mapping(uint256 => Campaign) public campaigns;
	mapping(uint256 => mapping(address => uint256)) public contributions;

	event CampaignCreated(uint256 indexed id, address indexed creator, string title, uint256 goal, uint256 deadline);
	event Contributed(uint256 indexed id, address indexed contributor, uint256 amount);
	event Refunded(uint256 indexed id, address indexed contributor, uint256 amount);
	event Claimed(uint256 indexed id, address indexed creator, uint256 amount);

	modifier onlyCreator(uint256 id) {
		require(campaigns[id].creator == msg.sender, "Not creator");
		_;
	}

	function createCampaign(
		string calldata title,
		string calldata description,
		uint256 goal,
		uint256 duration
	) external returns (uint256 id) {
		require(goal > 0, "Goal=0");
		require(duration > 0, "Duration=0");
		id = nextCampaignId++;
		Campaign storage c = campaigns[id];
		c.creator = msg.sender;
		c.title = title;
		c.description = description;
		c.goal = goal;
		c.deadline = block.timestamp + duration;
		emit CampaignCreated(id, msg.sender, title, goal, c.deadline);
	}

	function contribute(uint256 id) external payable {
		Campaign storage c = campaigns[id];
		require(c.creator != address(0), "No campaign");
		require(block.timestamp < c.deadline, "Ended");
		require(msg.value > 0, "No value");
		c.fundsRaised += msg.value;
		contributions[id][msg.sender] += msg.value;
		emit Contributed(id, msg.sender, msg.value);
	}

	function refund(uint256 id) external {
		Campaign storage c = campaigns[id];
		require(c.creator != address(0), "No campaign");
		require(block.timestamp >= c.deadline, "Not ended");
		require(c.fundsRaised < c.goal, "Goal met");
		uint256 amount = contributions[id][msg.sender];
		require(amount > 0, "Nothing to refund");
		contributions[id][msg.sender] = 0;
		(bool ok, ) = payable(msg.sender).call{value: amount}("");
		require(ok, "Refund failed");
		emit Refunded(id, msg.sender, amount);
	}

	function claim(uint256 id) external onlyCreator(id) {
		Campaign storage c = campaigns[id];
		require(block.timestamp >= c.deadline, "Not ended");
		require(c.fundsRaised >= c.goal, "Goal not met");
		require(!c.claimed, "Claimed");
		c.claimed = true;
		uint256 amount = c.fundsRaised;
		c.fundsRaised = 0;
		(bool ok, ) = payable(c.creator).call{value: amount}("");
		require(ok, "Claim failed");
		emit Claimed(id, c.creator, amount);
	}

	function getCampaign(uint256 id) external view returns (Campaign memory) {
		return campaigns[id];
	}
}

